1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const ALIKE_BLOCK_SIZE = 3;
5	const ALIKE_BLOCK_PREMIUM = 60;
6	
7	const BASE_PREMIUM: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	type Item = { type: string; cursed?: boolean };
17	type Step = { items: Item[] };
18	type Scenario = { steps: Step[] };
19	
20	const groupByType = (items: Item[]): Item[][] => {
21	  const groups = Map.groupBy(items, (item) => item.type);
22	  return Array.from(groups.values());
23	};
24	
25	const sumBasePremiums = (items: Item[]): number =>
26	  items.reduce((acc, { type }) => acc + BASE_PREMIUM[type], 0);
27	
28	const basePremiumForGroup = (group: Item[]): number =>
29	  group.length === ALIKE_BLOCK_SIZE ? ALIKE_BLOCK_PREMIUM : sumBasePremiums(group);
30	
31	const basePremiumForItems = (items: Item[]): number =>
32	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
33	
34	const itemSurcharges = (items: Item[]): number =>
35	  items.reduce(
36	    (sum, item) => sum + (item.cursed ? BASE_PREMIUM[item.type] * CURSED_SURCHARGE_RATE : 0),
37	    0,
38	  );
39	
40	const quotePremium = (items: Item[]): number => {
41	  const basePremium = basePremiumForItems(items);
42	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
43	  return Math.ceil(basePremium + itemSurcharges(items) + firstInsuranceSurcharge) + PROCESSING_FEE;
44	};
45	
46	export const runScenario = (scenario: Scenario): unknown => {
47	  const results = scenario.steps.map((step) => ({
48	    premium: quotePremium(step.items),
49	  }));
50	  return { results };
51	};
